  OP_REQUIRES(ctx, xh_tensor.dims() == 2,
              errors::InvalidArgument("xh_tensor must be rank 2 but is rank ",
                                      xh_tensor.dims(), "."));
  OP_REQUIRES(ctx, i_tensor->dims() == 2,
