  OP_REQUIRES(ctx, ci_tensor->dims() == 2,
              errors::InvalidArgument("ci_tensor must be rank 2 but is rank ",
                                      ci_tensor->dims(), "."));
  OP_REQUIRES(ctx, co_tensor->dims() == 2,
