Status TrySimplify(NodeDef* consumer, string* simplified_node_name) override {
  NodeDef* producer;

  if (consumer->input_size() < 1) {
    return errors::FailedPrecondition("Node ", simplified_node_name,
                                      " lacks inputs");
  }

  TF_RETURN_IF_ERROR(GetInputNode(consumer->input(0), &producer));
  const bool producer_is_cast = IsCastLike(*producer);
  const bool can_optimize =
      !IsCheckNumerics(*producer) &&
      ((producer_is_cast && IsValuePreserving(*consumer)) ||
       (IsValuePreserving(*producer) && IsCastLike(*consumer)));
  if (!can_optimize || IsControlFlow(*producer) ||
      IsInPreserveSet(*producer) ||
      producer->device() != consumer->device()) {
    return Status::OK();
  }

  const NodeDef* cast_like_node = producer_is_cast ? producer : consumer;
  const OpDef* cast_like_op_def = nullptr;
  TF_RETURN_IF_ERROR(OpRegistry::Global()->LookUpOpDef(cast_like_node->op(),
                                                       &cast_like_op_def));
  DataType cast_src_type;
  TF_RETURN_IF_ERROR(InputTypeForNode(*cast_like_node, *cast_like_op_def, 0,
                                      &cast_src_type));
  DataType cast_dst_type;
  TF_RETURN_IF_ERROR(OutputTypeForNode(*cast_like_node, *cast_like_op_def, 0,
                                       &cast_dst_type));
  if (!IsFixedSizeType(cast_src_type) || !IsFixedSizeType(cast_dst_type)) {
    return Status::OK();
  } else if (producer_is_cast &&
             DataTypeSize(cast_dst_type) <= DataTypeSize(cast_src_type)) {
    return Status::OK();
  } else if (!producer_is_cast &&
             DataTypeSize(cast_dst_type) >= DataTypeSize(cast_src_type)) {
    return Status::OK();
  }

  // Check that nodes were not already optimized.
  const string optimized_producer_name = OptimizedNodeName(
      ParseNodeScopeAndName(producer->name()), DataTypeString(cast_dst_type));
  const string optimized_consumer_name = OptimizedNodeName(
      ParseNodeScopeAndName(consumer->name()), DataTypeString(cast_src_type));
  const bool is_already_optimized =
      ctx().node_map->NodeExists(optimized_consumer_name) ||
      ctx().node_map->NodeExists(optimized_producer_name);
  if (is_already_optimized) {
    return Status::OK();
  }

  // Add copies of consumer and producer in reverse order.
  NodeDef* input;
  TF_RETURN_IF_ERROR(GetInputNode(producer->input(0), &input));
  // Create new producer node.
  NodeDef* new_producer = AddCopyNode(optimized_consumer_name, consumer);
  new_producer->set_input(0, producer->input(0));
  ctx().node_map->AddOutput(input->name(), new_producer->name());

  // Create new consumer node.
  NodeDef* new_consumer = AddCopyNode(optimized_producer_name, producer);
  new_consumer->set_input(0, new_producer->name());

  NodeDef* new_value_preserving =
      producer_is_cast ? new_producer : new_consumer;
  const DataType new_input_type =
      producer_is_cast ? cast_src_type : cast_dst_type;
  // Update the input type of the value-preserving node. The input and
  // output types of the cast-like nodes remain the same.
  TF_RETURN_IF_ERROR(SetInputType(new_input_type, new_value_preserving));
  // Make sure there is a kernel registered for the value preserving op
  // with the new input type.
  TF_RETURN_IF_ERROR(IsKernelRegisteredForNode(*new_value_preserving));
  ctx().node_map->AddOutput(new_producer->name(), new_consumer->name());

  AddToOptimizationQueue(new_producer);
  *simplified_node_name = new_consumer->name();

  return Status::OK();
}

Status TrySimplify(NodeDef* consumer, string* simplified_node_name) override {
  NodeDef* producer;
  TF_RETURN_IF_ERROR(GetInputNode(consumer->input(0), &producer));
  const bool producer_is_cast = IsCastLike(*producer);
  const bool can_optimize =
      !IsCheckNumerics(*producer) &&
      ((producer_is_cast && IsValuePreserving(*consumer)) ||
       (IsValuePreserving(*producer) && IsCastLike(*consumer)));
  if (!can_optimize || IsControlFlow(*producer) ||
      IsInPreserveSet(*producer) ||
      producer->device() != consumer->device()) {
    return Status::OK();
  }

  const NodeDef* cast_like_node = producer_is_cast ? producer : consumer;
  const OpDef* cast_like_op_def = nullptr;
  TF_RETURN_IF_ERROR(OpRegistry::Global()->LookUpOpDef(cast_like_node->op(),
                                                       &cast_like_op_def));
  DataType cast_src_type;
  TF_RETURN_IF_ERROR(InputTypeForNode(*cast_like_node, *cast_like_op_def, 0,
                                      &cast_src_type));
  DataType cast_dst_type;
  TF_RETURN_IF_ERROR(OutputTypeForNode(*cast_like_node, *cast_like_op_def, 0,
                                       &cast_dst_type));
  if (!IsFixedSizeType(cast_src_type) || !IsFixedSizeType(cast_dst_type)) {
    return Status::OK();
  } else if (producer_is_cast &&
             DataTypeSize(cast_dst_type) <= DataTypeSize(cast_src_type)) {
    return Status::OK();
  } else if (!producer_is_cast &&
             DataTypeSize(cast_dst_type) >= DataTypeSize(cast_src_type)) {
    return Status::OK();
  }

  // Check that nodes were not already optimized.
  const string optimized_producer_name = OptimizedNodeName(
      ParseNodeScopeAndName(producer->name()), DataTypeString(cast_dst_type));
  const string optimized_consumer_name = OptimizedNodeName(
      ParseNodeScopeAndName(consumer->name()), DataTypeString(cast_src_type));
  const bool is_already_optimized =
      ctx().node_map->NodeExists(optimized_consumer_name) ||
      ctx().node_map->NodeExists(optimized_producer_name);
  if (is_already_optimized) {
    return Status::OK();
  }

  // Add copies of consumer and producer in reverse order.
  NodeDef* input;
  TF_RETURN_IF_ERROR(GetInputNode(producer->input(0), &input));
  // Create new producer node.
  NodeDef* new_producer = AddCopyNode(optimized_consumer_name, consumer);
  new_producer->set_input(0, producer->input(0));
  ctx().node_map->AddOutput(input->name(), new_producer->name());

  // Create new consumer node.
  NodeDef* new_consumer = AddCopyNode(optimized_producer_name, producer);
  new_consumer->set_input(0, new_producer->name());

  NodeDef* new_value_preserving =
      producer_is_cast ? new_producer : new_consumer;
  const DataType new_input_type =
      producer_is_cast ? cast_src_type : cast_dst_type;
  // Update the input type of the value-preserving node. The input and
  // output types of the cast-like nodes remain the same.
  TF_RETURN_IF_ERROR(SetInputType(new_input_type, new_value_preserving));
  // Make sure there is a kernel registered for the value preserving op
  // with the new input type.
  TF_RETURN_IF_ERROR(IsKernelRegisteredForNode(*new_value_preserving));
  ctx().node_map->AddOutput(new_producer->name(), new_consumer->name());

  AddToOptimizationQueue(new_producer);
  *simplified_node_name = new_consumer->name();

  return Status::OK();
}

void CConnectionTransportUDPBase::Received_Data( const uint8 *pPkt, int cbPkt, SteamNetworkingMicroseconds usecNow )
{

	if ( cbPkt < sizeof(UDPDataMsgHdr) )
	{
		ReportBadUDPPacketFromConnectionPeer( "DataPacket", "Packet of size %d is too small.", cbPkt );
		return;
	}

	// Check cookie
	const UDPDataMsgHdr *hdr = (const UDPDataMsgHdr *)pPkt;
	if ( LittleDWord( hdr->m_unToConnectionID ) != ConnectionIDLocal() )
	{

		// Wrong session.  It could be an old session, or it could be spoofed.
		ReportBadUDPPacketFromConnectionPeer( "DataPacket", "Incorrect connection ID" );
		if ( BCheckGlobalSpamReplyRateLimit( usecNow ) )
		{
			SendNoConnection( LittleDWord( hdr->m_unToConnectionID ), 0 );
		}
		return;
	}
	uint16 nWirePktNumber = LittleWord( hdr->m_unSeqNum );

	// Check state
	switch ( ConnectionState() )
	{
		case k_ESteamNetworkingConnectionState_Dead:
		case k_ESteamNetworkingConnectionState_None:
		default:
			Assert( false );
			return;

		case k_ESteamNetworkingConnectionState_ClosedByPeer:
		case k_ESteamNetworkingConnectionState_FinWait:
		case k_ESteamNetworkingConnectionState_ProblemDetectedLocally:
			SendConnectionClosedOrNoConnection();
			return;

		case k_ESteamNetworkingConnectionState_Connecting:
			// Ignore it.  We don't have the SteamID of whoever is on the other end yet,
			// their encryption keys, etc.  The most likely cause is that a server sent
			// a ConnectOK, which dropped.  So they think we're connected but we don't
			// have everything yet.
			return;

		case k_ESteamNetworkingConnectionState_Linger:
		case k_ESteamNetworkingConnectionState_Connected:
		case k_ESteamNetworkingConnectionState_FindingRoute: // not used for raw UDP, but might be used for derived class

			// We'll process the chunk
			break;
	}

	const uint8 *pIn = pPkt + sizeof(*hdr);
	const uint8 *pPktEnd = pPkt + cbPkt;

	// Inline stats?
	static CMsgSteamSockets_UDP_Stats msgStats;
	CMsgSteamSockets_UDP_Stats *pMsgStatsIn = nullptr;
	uint32 cbStatsMsgIn = 0;
	if ( hdr->m_unMsgFlags & hdr->kFlag_ProtobufBlob )
	{
		//Msg_Verbose( "Received inline stats from %s", server.m_szName );

		pIn = DeserializeVarInt( pIn, pPktEnd, cbStatsMsgIn );
		if ( pIn == NULL )
		{
			ReportBadUDPPacketFromConnectionPeer( "DataPacket", "Failed to varint decode size of stats blob" );
			return;
		}
		if ( cbStatsMsgIn > pPktEnd - pIn )
		{
			ReportBadUDPPacketFromConnectionPeer( "DataPacket", "stats message size doesn't make sense.  Stats message size %u, packet size %d", cbStatsMsgIn, cbPkt );
			return;
		}

		if ( !msgStats.ParseFromArray( pIn, cbStatsMsgIn ) )
		{
			ReportBadUDPPacketFromConnectionPeer( "DataPacket", "protobuf failed to parse inline stats message" );
			return;
		}

		// Shove sequence number so we know what acks to pend, etc
		pMsgStatsIn = &msgStats;

		// Advance pointer
		pIn += cbStatsMsgIn;
	}

	const void *pChunk = pIn;
	int cbChunk = pPktEnd - pIn;

	// Decrypt it, and check packet number
	UDPRecvPacketContext_t ctx;
	ctx.m_usecNow = usecNow;
	ctx.m_pTransport = this;
	ctx.m_pStatsIn = pMsgStatsIn;
	if ( !m_connection.DecryptDataChunk( nWirePktNumber, cbPkt, pChunk, cbChunk, ctx ) )
		return;

	// This is a valid packet.  P2P connections might want to make a note of this
	RecvValidUDPDataPacket( ctx );

	// Process plaintext
	int usecTimeSinceLast = 0; // FIXME - should we plumb this through so we can measure jitter?
	if ( !m_connection.ProcessPlainTextDataChunk( usecTimeSinceLast, ctx ) )
		return;

	// Process the stats, if any
	if ( pMsgStatsIn )
		RecvStats( *pMsgStatsIn, usecNow );
}

