std::string& attrf(int ncid, int varId, const char * attrName, std::string& alloc)
{
    size_t len = 0;
    nc_inq_attlen(ncid, varId, attrName, &len);

    if(len < 1)
    {
        alloc.clear();
        return alloc;
    }

    alloc.resize(len);
    memset(&alloc[0], 0, len);

    // Now look through this variable for the attribute
    nc_get_att_text(ncid, varId, attrName, &alloc[0]);

    return alloc;
}

std::string& attrf(int ncid, int varId, const char * attrName, std::string& alloc)
{
    alloc = "";

    size_t len = 0;
    nc_inq_attlen(ncid, varId, attrName, &len);

    if(len < 1)
    {
        return alloc;
    }

    char attr_vals[NC_MAX_NAME + 1];
    memset(attr_vals, 0, NC_MAX_NAME + 1);

    // Now look through this variable for the attribute
    if(nc_get_att_text(ncid, varId, attrName, attr_vals) != NC_NOERR)
    {
        return alloc;
    }

    alloc = std::string(attr_vals);
    return alloc;
}

void Image::printIFDStructure(BasicIo& io, std::ostream& out, Exiv2::PrintStructureOption option,uint32_t start,bool bSwap,char c,int depth)
{
    depth++;
    bool bFirst  = true  ;

    // buffer
    const size_t dirSize = 32;
    DataBuf  dir(dirSize);
    bool bPrint = option == kpsBasic || option == kpsRecursive;

    do {
        // Read top of directory
        const int seekSuccess = !io.seek(start,BasicIo::beg);
        const long bytesRead = io.read(dir.pData_, 2);
        if (!seekSuccess || bytesRead == 0) {
            throw Error(kerCorruptedMetadata);
        }
        uint16_t   dirLength = byteSwap2(dir,0,bSwap);

        bool tooBig = dirLength > 500;
        if ( tooBig ) throw Error(kerTiffDirectoryTooLarge);

        if ( bFirst && bPrint ) {
            out << Internal::indent(depth) << Internal::stringFormat("STRUCTURE OF TIFF FILE (%c%c): ",c,c) << io.path() << std::endl;
            if ( tooBig ) out << Internal::indent(depth) << "dirLength = " << dirLength << std::endl;
        }

        // Read the dictionary
        for ( int i = 0 ; i < dirLength ; i ++ ) {
            if ( bFirst && bPrint ) {
                out << Internal::indent(depth)
                    << " address |    tag                              |     "
                    << " type |    count |    offset | value\n";
            }
            bFirst = false;

            io.read(dir.pData_, 12);
            uint16_t tag    = byteSwap2(dir,0,bSwap);
            uint16_t type   = byteSwap2(dir,2,bSwap);
            uint32_t count  = byteSwap4(dir,4,bSwap);
            uint32_t offset = byteSwap4(dir,8,bSwap);

            // Break for unknown tag types else we may segfault.
            if ( !typeValid(type) ) {
                std::cerr << "invalid type value detected in Image::printIFDStructure:  " << type << std::endl;
                start = 0; // break from do loop
                throw Error(kerInvalidTypeValue);
            }

            std::string sp  = "" ; // output spacer

            //prepare to print the value
            uint32_t kount  = isPrintXMP(tag,option) ? count // haul in all the data
                            : isPrintICC(tag,option) ? count // ditto
                            : isStringType(type)     ? (count > 32 ? 32 : count) // restrict long arrays
                            : count > 5              ? 5
                            : count
                            ;
            uint32_t pad    = isStringType(type) ? 1 : 0;
            uint32_t size   = isStringType(type) ? 1
                            : is2ByteType(type)  ? 2
                            : is4ByteType(type)  ? 4
                            : is8ByteType(type)  ? 8
                            : 1
                            ;

            // if ( offset > io.size() ) offset = 0; // Denial of service?

            // #55 and #56 memory allocation crash test/data/POC8
            long long allocate = (long long) size*count + pad+20;
            if ( allocate > (long long) io.size() ) {
                throw Error(kerInvalidMalloc);
            }
            DataBuf  buf((long)allocate);  // allocate a buffer
            std::memset(buf.pData_, 0, buf.size_);
            std::memcpy(buf.pData_,dir.pData_+8,4);  // copy dir[8:11] into buffer (short strings)
            const bool bOffsetIsPointer = count*size > 4;

            if ( bOffsetIsPointer ) {         // read into buffer
                size_t   restore = io.tell();  // save
                io.seek(offset,BasicIo::beg);  // position
                io.read(buf.pData_,count*size);// read
                io.seek(restore,BasicIo::beg); // restore
            }

            if ( bPrint ) {
                const uint32_t address = start + 2 + i*12 ;
                const std::string offsetString = bOffsetIsPointer?
                    Internal::stringFormat("%10u", offset):
                    "";

                out << Internal::indent(depth)
                << Internal::stringFormat("%8u | %#06x %-28s |%10s |%9u |%10s | "
                                          ,address,tag,tagName(tag).c_str(),typeName(type),count,offsetString.c_str());
                if ( isShortType(type) ){
                    for ( size_t k = 0 ; k < kount ; k++ ) {
                        out << sp << byteSwap2(buf,k*size,bSwap);
                        sp = " ";
                    }
                } else if ( isLongType(type) ){
                    for ( size_t k = 0 ; k < kount ; k++ ) {
                        out << sp << byteSwap4(buf,k*size,bSwap);
                        sp = " ";
                    }

                } else if ( isRationalType(type) ){
                    for ( size_t k = 0 ; k < kount ; k++ ) {
                        uint32_t a = byteSwap4(buf,k*size+0,bSwap);
                        uint32_t b = byteSwap4(buf,k*size+4,bSwap);
                        out << sp << a << "/" << b;
                        sp = " ";
                    }
                } else if ( isStringType(type) ) {
                    out << sp << Internal::binaryToString(makeSlice(buf, 0, kount));
                }

                sp = kount == count ? "" : " ...";
                out << sp << std::endl;

                if ( option == kpsRecursive && (tag == 0x8769 /* ExifTag */ || tag == 0x014a/*SubIFDs*/  || type == tiffIfd) ) {
                    for ( size_t k = 0 ; k < count ; k++ ) {
                        size_t   restore = io.tell();
                        uint32_t offset = byteSwap4(buf,k*size,bSwap);
                        printIFDStructure(io,out,option,offset,bSwap,c,depth);
                        io.seek(restore,BasicIo::beg);
                    }
                } else if ( option == kpsRecursive && tag == 0x83bb /* IPTCNAA */ ) {

                    if (static_cast<size_t>(Safe::add(count, offset)) > io.size()) {
                        throw Error(kerCorruptedMetadata);
                    }

                    const size_t restore = io.tell();
                    io.seek(offset, BasicIo::beg);  // position
                    std::vector<byte> bytes(count) ;  // allocate memory
                    // TODO: once we have C++11 use bytes.data()
                    const long read_bytes = io.read(&bytes[0], count);
                    io.seek(restore, BasicIo::beg);
                    // TODO: once we have C++11 use bytes.data()
                    IptcData::printStructure(out, makeSliceUntil(&bytes[0], read_bytes), depth);

                }  else if ( option == kpsRecursive && tag == 0x927c /* MakerNote */ && count > 10) {
                    size_t   restore = io.tell();  // save

                    uint32_t jump= 10           ;
                    byte     bytes[20]          ;
                    const char* chars = (const char*) &bytes[0] ;
                    io.seek(offset,BasicIo::beg);  // position
                    io.read(bytes,jump    )     ;  // read
                    bytes[jump]=0               ;
                    if ( ::strcmp("Nikon",chars) == 0 ) {
                        // tag is an embedded tiff
                        byte* bytes=new byte[count-jump] ;  // allocate memory
                        io.read(bytes,count-jump)        ;  // read
                        MemIo memIo(bytes,count-jump)    ;  // create a file
                        printTiffStructure(memIo,out,option,depth);
                        delete[] bytes                   ;  // free
                    } else {
                        // tag is an IFD
                        io.seek(0,BasicIo::beg);  // position
                        printIFDStructure(io,out,option,offset,bSwap,c,depth);
                    }

                    io.seek(restore,BasicIo::beg); // restore
                }
            }

            if ( isPrintXMP(tag,option) ) {
                buf.pData_[count]=0;
                out << (char*) buf.pData_;
            }
            if ( isPrintICC(tag,option) ) {
                out.write((const char*)buf.pData_,count);
            }
        }
        if ( start ) {
            io.read(dir.pData_, 4);
            start = tooBig ? 0 : byteSwap4(dir,0,bSwap);
        }
    } while (start) ;

    if ( bPrint ) {
        out << Internal::indent(depth) << "END " << io.path() << std::endl;
    }
    out.flush();
    depth--;
}

void Image::printIFDStructure(BasicIo& io, std::ostream& out, Exiv2::PrintStructureOption option,uint32_t start,bool bSwap,char c,int depth)
{
    depth++;
    bool bFirst  = true  ;

    // buffer
    const size_t dirSize = 32;
    DataBuf  dir(dirSize);
    bool bPrint = option == kpsBasic || option == kpsRecursive;

    do {
        // Read top of directory
        io.seek(start,BasicIo::beg);
        io.read(dir.pData_, 2);
        uint16_t   dirLength = byteSwap2(dir,0,bSwap);

        bool tooBig = dirLength > 500;
        if ( tooBig ) throw Error(kerTiffDirectoryTooLarge);

        if ( bFirst && bPrint ) {
            out << Internal::indent(depth) << Internal::stringFormat("STRUCTURE OF TIFF FILE (%c%c): ",c,c) << io.path() << std::endl;
            if ( tooBig ) out << Internal::indent(depth) << "dirLength = " << dirLength << std::endl;
        }

        // Read the dictionary
        for ( int i = 0 ; i < dirLength ; i ++ ) {
            if ( bFirst && bPrint ) {
                out << Internal::indent(depth)
                    << " address |    tag                              |     "
                    << " type |    count |    offset | value\n";
            }
            bFirst = false;

            io.read(dir.pData_, 12);
            uint16_t tag    = byteSwap2(dir,0,bSwap);
            uint16_t type   = byteSwap2(dir,2,bSwap);
            uint32_t count  = byteSwap4(dir,4,bSwap);
            uint32_t offset = byteSwap4(dir,8,bSwap);

            // Break for unknown tag types else we may segfault.
            if ( !typeValid(type) ) {
                std::cerr << "invalid type value detected in Image::printIFDStructure:  " << type << std::endl;
                start = 0; // break from do loop
                throw Error(kerInvalidTypeValue);
            }

            std::string sp  = "" ; // output spacer

            //prepare to print the value
            uint32_t kount  = isPrintXMP(tag,option) ? count // haul in all the data
                            : isPrintICC(tag,option) ? count // ditto
                            : isStringType(type)     ? (count > 32 ? 32 : count) // restrict long arrays
                            : count > 5              ? 5
                            : count
                            ;
            uint32_t pad    = isStringType(type) ? 1 : 0;
            uint32_t size   = isStringType(type) ? 1
                            : is2ByteType(type)  ? 2
                            : is4ByteType(type)  ? 4
                            : is8ByteType(type)  ? 8
                            : 1
                            ;

            // if ( offset > io.size() ) offset = 0; // Denial of service?

            // #55 and #56 memory allocation crash test/data/POC8
            long long allocate = (long long) size*count + pad+20;
            if ( allocate > (long long) io.size() ) {
                throw Error(kerInvalidMalloc);
            }
            DataBuf  buf((long)allocate);  // allocate a buffer
            std::memset(buf.pData_, 0, buf.size_);
            std::memcpy(buf.pData_,dir.pData_+8,4);  // copy dir[8:11] into buffer (short strings)
            const bool bOffsetIsPointer = count*size > 4;

            if ( bOffsetIsPointer ) {         // read into buffer
                size_t   restore = io.tell();  // save
                io.seek(offset,BasicIo::beg);  // position
                io.read(buf.pData_,count*size);// read
                io.seek(restore,BasicIo::beg); // restore
            }

            if ( bPrint ) {
                const uint32_t address = start + 2 + i*12 ;
                const std::string offsetString = bOffsetIsPointer?
                    Internal::stringFormat("%10u", offset):
                    "";

                out << Internal::indent(depth)
                << Internal::stringFormat("%8u | %#06x %-28s |%10s |%9u |%10s | "
                                          ,address,tag,tagName(tag).c_str(),typeName(type),count,offsetString.c_str());
                if ( isShortType(type) ){
                    for ( size_t k = 0 ; k < kount ; k++ ) {
                        out << sp << byteSwap2(buf,k*size,bSwap);
                        sp = " ";
                    }
                } else if ( isLongType(type) ){
                    for ( size_t k = 0 ; k < kount ; k++ ) {
                        out << sp << byteSwap4(buf,k*size,bSwap);
                        sp = " ";
                    }

                } else if ( isRationalType(type) ){
                    for ( size_t k = 0 ; k < kount ; k++ ) {
                        uint32_t a = byteSwap4(buf,k*size+0,bSwap);
                        uint32_t b = byteSwap4(buf,k*size+4,bSwap);
                        out << sp << a << "/" << b;
                        sp = " ";
                    }
                } else if ( isStringType(type) ) {
                    out << sp << Internal::binaryToString(makeSlice(buf, 0, kount));
                }

                sp = kount == count ? "" : " ...";
                out << sp << std::endl;

                if ( option == kpsRecursive && (tag == 0x8769 /* ExifTag */ || tag == 0x014a/*SubIFDs*/  || type == tiffIfd) ) {
                    for ( size_t k = 0 ; k < count ; k++ ) {
                        size_t   restore = io.tell();
                        uint32_t offset = byteSwap4(buf,k*size,bSwap);
                        printIFDStructure(io,out,option,offset,bSwap,c,depth);
                        io.seek(restore,BasicIo::beg);
                    }
                } else if ( option == kpsRecursive && tag == 0x83bb /* IPTCNAA */ ) {

                    if (static_cast<size_t>(Safe::add(count, offset)) > io.size()) {
                        throw Error(kerCorruptedMetadata);
                    }

                    const size_t restore = io.tell();
                    io.seek(offset, BasicIo::beg);  // position
                    std::vector<byte> bytes(count) ;  // allocate memory
                    // TODO: once we have C++11 use bytes.data()
                    const long read_bytes = io.read(&bytes[0], count);
                    io.seek(restore, BasicIo::beg);
                    // TODO: once we have C++11 use bytes.data()
                    IptcData::printStructure(out, makeSliceUntil(&bytes[0], read_bytes), depth);

                }  else if ( option == kpsRecursive && tag == 0x927c /* MakerNote */ && count > 10) {
                    size_t   restore = io.tell();  // save

                    uint32_t jump= 10           ;
                    byte     bytes[20]          ;
                    const char* chars = (const char*) &bytes[0] ;
                    io.seek(offset,BasicIo::beg);  // position
                    io.read(bytes,jump    )     ;  // read
                    bytes[jump]=0               ;
                    if ( ::strcmp("Nikon",chars) == 0 ) {
                        // tag is an embedded tiff
                        byte* bytes=new byte[count-jump] ;  // allocate memory
                        io.read(bytes,count-jump)        ;  // read
                        MemIo memIo(bytes,count-jump)    ;  // create a file
                        printTiffStructure(memIo,out,option,depth);
                        delete[] bytes                   ;  // free
                    } else {
                        // tag is an IFD
                        io.seek(0,BasicIo::beg);  // position
                        printIFDStructure(io,out,option,offset,bSwap,c,depth);
                    }

                    io.seek(restore,BasicIo::beg); // restore
                }
            }

            if ( isPrintXMP(tag,option) ) {
                buf.pData_[count]=0;
                out << (char*) buf.pData_;
            }
            if ( isPrintICC(tag,option) ) {
                out.write((const char*)buf.pData_,count);
            }
        }
        if ( start ) {
            io.read(dir.pData_, 4);
            start = tooBig ? 0 : byteSwap4(dir,0,bSwap);
        }
    } while (start) ;

    if ( bPrint ) {
        out << Internal::indent(depth) << "END " << io.path() << std::endl;
    }
    out.flush();
    depth--;
}

int DCTStream::getChars(int nChars, unsigned char *buffer)
{
    for (int i = 0; i < nChars;) {
        if (current == limit) {
            if (!readLine())
                return i;
        }
        int left = limit - current;
        if (left + i > nChars)
            left = nChars - i;
        memcpy(buffer + i, current, left);
        current += left;
        i += left;
    }
    return nChars;
}

int DCTStream::getChars(int nChars, unsigned char *buffer)
{
    for (int i = 0; i < nChars;) {
        if (current == limit) {
            if (!readLine())
                return i;
        }
        int left = limit - current;
        if (nChars < left)
            left = nChars;
        memcpy(buffer + i, current, left);
        current += left;
        i += left;
    }
    return nChars;
}

size_t olm_pk_decrypt(
    OlmPkDecryption * decryption,
    void const * ephemeral_key, size_t ephemeral_key_length,
    void const * mac, size_t mac_length,
    void * ciphertext, size_t ciphertext_length,
    void * plaintext, size_t max_plaintext_length
) {
    if (max_plaintext_length
            < olm_pk_max_plaintext_length(decryption, ciphertext_length)) {
        decryption->last_error =
            OlmErrorCode::OLM_OUTPUT_BUFFER_TOO_SMALL;
        return std::size_t(-1);
    }

    size_t raw_ciphertext_length = olm::decode_base64_length(ciphertext_length);

    if (ephemeral_key_length != olm::encode_base64_length(CURVE25519_KEY_LENGTH)
        || mac_length != olm::encode_base64_length(MAC_LENGTH)
        || raw_ciphertext_length == std::size_t(-1)) {
        decryption->last_error = OlmErrorCode::OLM_INVALID_BASE64;
        return std::size_t(-1);
    }

    struct _olm_curve25519_public_key ephemeral;
    olm::decode_base64(
        (const uint8_t*)ephemeral_key,
        olm::encode_base64_length(CURVE25519_KEY_LENGTH),
        (uint8_t *)ephemeral.public_key
    );

    olm::SharedKey secret;
    _olm_crypto_curve25519_shared_secret(&decryption->key_pair, &ephemeral, secret);

    uint8_t raw_mac[MAC_LENGTH];
    olm::decode_base64(
        (const uint8_t *)mac,
        olm::encode_base64_length(MAC_LENGTH),
        raw_mac
    );

    olm::decode_base64(
        (const uint8_t *)ciphertext,
        ciphertext_length,
        (uint8_t *)ciphertext
    );

    size_t result = _olm_cipher_aes_sha_256_ops.decrypt(
        olm_pk_cipher,
        secret, sizeof(secret),
        (uint8_t *) raw_mac, MAC_LENGTH,
        (const uint8_t *) ciphertext, raw_ciphertext_length,
        (uint8_t *) plaintext, max_plaintext_length
    );
    if (result == std::size_t(-1)) {
        // we already checked the buffer sizes, so the only error that decrypt
        // will return is if the MAC is incorrect
        decryption->last_error =
            OlmErrorCode::OLM_BAD_MESSAGE_MAC;
        return std::size_t(-1);
    } else {
        return result;
    }
}

size_t olm_pk_decrypt(
    OlmPkDecryption * decryption,
    void const * ephemeral_key, size_t ephemeral_key_length,
    void const * mac, size_t mac_length,
    void * ciphertext, size_t ciphertext_length,
    void * plaintext, size_t max_plaintext_length
) {
    if (max_plaintext_length
            < olm_pk_max_plaintext_length(decryption, ciphertext_length)) {
        decryption->last_error =
            OlmErrorCode::OLM_OUTPUT_BUFFER_TOO_SMALL;
        return std::size_t(-1);
    }

    struct _olm_curve25519_public_key ephemeral;
    olm::decode_base64(
        (const uint8_t*)ephemeral_key, ephemeral_key_length,
        (uint8_t *)ephemeral.public_key
    );
    olm::SharedKey secret;
    _olm_crypto_curve25519_shared_secret(&decryption->key_pair, &ephemeral, secret);
    uint8_t raw_mac[MAC_LENGTH];
    olm::decode_base64((const uint8_t*)mac, olm::encode_base64_length(MAC_LENGTH), raw_mac);
    size_t raw_ciphertext_length = olm::decode_base64_length(ciphertext_length);
    olm::decode_base64((const uint8_t *)ciphertext, ciphertext_length, (uint8_t *)ciphertext);
    size_t result = _olm_cipher_aes_sha_256_ops.decrypt(
        olm_pk_cipher,
        secret, sizeof(secret),
        (uint8_t *) raw_mac, MAC_LENGTH,
        (const uint8_t *) ciphertext, raw_ciphertext_length,
        (uint8_t *) plaintext, max_plaintext_length
    );
    if (result == std::size_t(-1)) {
        // we already checked the buffer sizes, so the only error that decrypt
        // will return is if the MAC is incorrect
        decryption->last_error =
            OlmErrorCode::OLM_BAD_MESSAGE_MAC;
        return std::size_t(-1);
    } else {
        return result;
    }
}

extract_VOMS_info( globus_gsi_cred_handle_t cred_handle, int verify_type, char **voname, char **firstfqan, char **quoted_DN_and_FQAN)
{

#if !defined(HAVE_EXT_VOMS)
	return 1;
#else

	int ret;
	struct vomsdata *voms_data = NULL;
	struct voms *voms_cert  = NULL;
	char *subject_name = NULL;
	char **fqan = NULL;
	int voms_err;
	int fqan_len = 0;
	char *retfqan = NULL;
	char *tmp_scan_ptr = NULL;

	STACK_OF(X509) *chain = NULL;
	X509 *cert = NULL;

	char* x509_fqan_delimiter = NULL;

	if ( activate_globus_gsi() != 0 ) {
		return 1;
	}

	// calling this function on something that doesn't have VOMS attributes
	// should return error 1.  when the config knob disables VOMS, behave the
	// same way.
	if (!param_boolean_int("USE_VOMS_ATTRIBUTES", 1)) {
		return 1;
	}

	ret = (*globus_gsi_cred_get_cert_chain_ptr)(cred_handle, &chain);
	if(ret != GLOBUS_SUCCESS) {
		ret = 10;
		goto end;
	}

	ret = (*globus_gsi_cred_get_cert_ptr)(cred_handle, &cert);
	if(ret != GLOBUS_SUCCESS) {
		ret = 11;
		goto end;
	}

	if ((*globus_gsi_cred_get_identity_name_ptr)(cred_handle, &subject_name)) {
		set_error_string( "unable to extract subject name" );
		ret = 12;
		goto end;
	}

	voms_data = (*VOMS_Init_ptr)(NULL, NULL);
	if (voms_data == NULL) {
		ret = 13;
		goto end;
	}

	if (verify_type == 0) {
		ret = (*VOMS_SetVerificationType_ptr)( VERIFY_NONE, voms_data, &voms_err );
		if (ret == 0) {
			(*VOMS_ErrorMessage_ptr)(voms_data, voms_err, NULL, 0);
			ret = voms_err;
			goto end;
		}
	}

	ret = (*VOMS_Retrieve_ptr)(cert, chain, RECURSE_CHAIN,
						voms_data, &voms_err);
	if (ret == 0) {
		if (voms_err == VERR_NOEXT) {
			// No VOMS extensions present
			ret = 1;
			goto end;
		} else {
			(*VOMS_ErrorMessage_ptr)(voms_data, voms_err, NULL, 0);
			ret = voms_err;
			goto end;
		}
	}

	// we only support one cert for now.  serializing and encoding all the
	// attributes is bad enough, i don't want to deal with doing this to
	// multiple certs.
	voms_cert = voms_data->data[0];

	if (voms_cert == NULL) {
		// No VOMS certs?? Treat like VOMS_Retrieve() returned VERR_NOEXT.
		ret = 1;
		goto end;
	}

	// fill in the unquoted versions of things
	if(voname) {
		*voname = strdup(voms_cert->voname ? voms_cert->voname : "");
	}

	if(firstfqan) {
		*firstfqan = strdup(voms_cert->fqan[0] ? voms_cert->fqan[0] : "");
	}

	// only construct the quoted_DN_and_FQAN if needed
	if (quoted_DN_and_FQAN) {
		// get our delimiter and trim it
		if (!(x509_fqan_delimiter = param("X509_FQAN_DELIMITER"))) {
			x509_fqan_delimiter = strdup(",");
		}
		tmp_scan_ptr = trim_quotes(x509_fqan_delimiter);
		free(x509_fqan_delimiter);
		x509_fqan_delimiter = tmp_scan_ptr;

		// calculate the length
		fqan_len = 0;

		// start with the length of the quoted DN
		tmp_scan_ptr = quote_x509_string( subject_name );
		fqan_len += strlen( tmp_scan_ptr );
		free(tmp_scan_ptr);

		// add the length of delimiter plus each voms attribute
		for (fqan = voms_cert->fqan; fqan && *fqan; fqan++) {
			// delimiter
			fqan_len += strlen(x509_fqan_delimiter);

			tmp_scan_ptr = quote_x509_string( *fqan );
			fqan_len += strlen( tmp_scan_ptr );
			free(tmp_scan_ptr);
		}

		// now malloc enough room for the quoted DN, quoted attrs, delimiters, and
		// NULL terminator
		retfqan = (char*) malloc (fqan_len+1);
		*retfqan = 0;  // set null terminiator

		// reset length counter -- we use this for efficient appending.
		fqan_len = 0;

		// start with the quoted DN
		tmp_scan_ptr = quote_x509_string( subject_name );
		strcat(retfqan, tmp_scan_ptr);
		fqan_len += strlen( tmp_scan_ptr );
		free(tmp_scan_ptr);

		// add the delimiter plus each voms attribute
		for (fqan = voms_cert->fqan; fqan && *fqan; fqan++) {
			// delimiter
			strcat(&(retfqan[fqan_len]), x509_fqan_delimiter);
			fqan_len += strlen(x509_fqan_delimiter);

			tmp_scan_ptr = quote_x509_string( *fqan );
			strcat(&(retfqan[fqan_len]), tmp_scan_ptr);
			fqan_len += strlen( tmp_scan_ptr );
			free(tmp_scan_ptr);
		}

		*quoted_DN_and_FQAN = retfqan;
	}

	ret = 0;

end:
	free(subject_name);
	free(x509_fqan_delimiter);
	if (voms_data)
		(*VOMS_Destroy_ptr)(voms_data);
	if (cert)
		X509_free(cert);
	if(chain)
		sk_X509_pop_free(chain, X509_free);

	return ret;
#endif

}

