CallResult<bool> JSObject::putComputedWithReceiver_RJS(
    Handle<JSObject> selfHandle,
    Runtime *runtime,
    Handle<> nameValHandle,
    Handle<> valueHandle,
    Handle<> receiver,
    PropOpFlags opFlags) {
  assert(
      !opFlags.getMustExist() &&
      "mustExist flag cannot be used with computed properties");

  // Try the fast-path first: has "index-like" properties, the "name"
  // already is a valid integer index, selfHandle and receiver are the
  // same, and it is present in storage.
  if (selfHandle->flags_.fastIndexProperties) {
    if (auto arrayIndex = toArrayIndexFastPath(*nameValHandle)) {
      if (selfHandle.getHermesValue().getRaw() == receiver->getRaw()) {
        if (haveOwnIndexed(selfHandle.get(), runtime, *arrayIndex)) {
          auto result =
              setOwnIndexed(selfHandle, runtime, *arrayIndex, valueHandle);
          if (LLVM_UNLIKELY(result == ExecutionStatus::EXCEPTION))
            return ExecutionStatus::EXCEPTION;
          if (LLVM_LIKELY(*result))
            return true;
          if (opFlags.getThrowOnError()) {
            // TODO: better message.
            return runtime->raiseTypeError(
                "Cannot assign to read-only property");
          }
          return false;
        }
      }
    }
  }

  // If nameValHandle is an object, we should convert it to string now,
  // because toString may have side-effect, and we want to do this only
  // once.
  auto converted = toPropertyKeyIfObject(runtime, nameValHandle);
  if (LLVM_UNLIKELY(converted == ExecutionStatus::EXCEPTION)) {
    return ExecutionStatus::EXCEPTION;
  }
  auto nameValPrimitiveHandle = *converted;

  ComputedPropertyDescriptor desc;

  // Look for the property in this object or along the prototype chain.
  MutableHandle<JSObject> propObj{runtime};
  if (LLVM_UNLIKELY(
          getComputedPrimitiveDescriptor(
              selfHandle, runtime, nameValPrimitiveHandle, propObj, desc) ==
          ExecutionStatus::EXCEPTION)) {
    return ExecutionStatus::EXCEPTION;
  }

  // If the property exists (or, we hit a proxy/hostobject on the way
  // up the chain)
  if (propObj) {
    // Get the simple case out of the way: If the property already
    // exists on selfHandle, is not an accessor, selfHandle and
    // receiver are the same, selfHandle is not a host
    // object/proxy/internal setter, and the property is writable,
    // just write into the same slot.

    if (LLVM_LIKELY(
            selfHandle == propObj &&
            selfHandle.getHermesValue().getRaw() == receiver->getRaw() &&
            !desc.flags.accessor && !desc.flags.internalSetter &&
            !desc.flags.hostObject && !desc.flags.proxyObject &&
            desc.flags.writable)) {
      if (LLVM_UNLIKELY(
              setComputedSlotValue(selfHandle, runtime, desc, valueHandle) ==
              ExecutionStatus::EXCEPTION)) {
        return ExecutionStatus::EXCEPTION;
      }
      return true;
    }

    // Is it an accessor?
    if (LLVM_UNLIKELY(desc.flags.accessor)) {
      auto *accessor = vmcast<PropertyAccessor>(
          getComputedSlotValue(propObj.get(), runtime, desc));

      // If it is a read-only accessor, fail.
      if (!accessor->setter) {
        if (opFlags.getThrowOnError()) {
          return runtime->raiseTypeErrorForValue(
              "Cannot assign to property ",
              nameValPrimitiveHandle,
              " which has only a getter");
        }
        return false;
      }

      // Execute the accessor on this object.
      if (accessor->setter.get(runtime)->executeCall1(
              runtime->makeHandle(accessor->setter),
              runtime,
              receiver,
              valueHandle.get()) == ExecutionStatus::EXCEPTION) {
        return ExecutionStatus::EXCEPTION;
      }
      return true;
    }

    if (LLVM_UNLIKELY(desc.flags.proxyObject)) {
      assert(
          !opFlags.getMustExist() &&
          "MustExist cannot be used with Proxy objects");
      CallResult<Handle<>> key = toPropertyKey(runtime, nameValPrimitiveHandle);
      if (key == ExecutionStatus::EXCEPTION)
        return ExecutionStatus::EXCEPTION;
      CallResult<bool> setRes =
          JSProxy::setComputed(propObj, runtime, *key, valueHandle, receiver);
      if (LLVM_UNLIKELY(setRes == ExecutionStatus::EXCEPTION)) {
        return ExecutionStatus::EXCEPTION;
      }
      if (!*setRes && opFlags.getThrowOnError()) {
        // TODO: better message.
        return runtime->raiseTypeError(
            TwineChar16("Proxy trap returned false for property"));
      }
      return setRes;
    }

    if (LLVM_UNLIKELY(!desc.flags.writable)) {
      if (desc.flags.staticBuiltin) {
        SymbolID id{};
        LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);
        return raiseErrorForOverridingStaticBuiltin(
            selfHandle, runtime, runtime->makeHandle(id));
      }
      if (opFlags.getThrowOnError()) {
        return runtime->raiseTypeErrorForValue(
            "Cannot assign to read-only property ", nameValPrimitiveHandle, "");
      }
      return false;
    }

    if (selfHandle == propObj && desc.flags.internalSetter) {
      SymbolID id{};
      LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);
      return internalSetter(
          selfHandle,
          runtime,
          id,
          desc.castToNamedPropertyDescriptorRef(),
          valueHandle,
          opFlags);
    }
  }

  // The property does not exist as an conventional own property on
  // this object.

  MutableHandle<JSObject> receiverHandle{runtime, *selfHandle};
  if (selfHandle.getHermesValue().getRaw() != receiver->getRaw() ||
      receiverHandle->isHostObject() || receiverHandle->isProxyObject()) {
    if (selfHandle.getHermesValue().getRaw() != receiver->getRaw()) {
      receiverHandle = dyn_vmcast<JSObject>(*receiver);
    }
    if (!receiverHandle) {
      return false;
    }
    CallResult<bool> descDefinedRes = getOwnComputedPrimitiveDescriptor(
        receiverHandle, runtime, nameValPrimitiveHandle, IgnoreProxy::No, desc);
    if (LLVM_UNLIKELY(descDefinedRes == ExecutionStatus::EXCEPTION)) {
      return ExecutionStatus::EXCEPTION;
    }
    DefinePropertyFlags dpf;
    if (*descDefinedRes) {
      if (LLVM_UNLIKELY(desc.flags.accessor || !desc.flags.writable)) {
        return false;
      }

      if (LLVM_LIKELY(
              !desc.flags.internalSetter && !receiverHandle->isHostObject() &&
              !receiverHandle->isProxyObject())) {
        if (LLVM_UNLIKELY(
                setComputedSlotValue(
                    receiverHandle, runtime, desc, valueHandle) ==
                ExecutionStatus::EXCEPTION)) {
          return ExecutionStatus::EXCEPTION;
        }
        return true;
      }
    }

    if (LLVM_UNLIKELY(
            desc.flags.internalSetter || receiverHandle->isHostObject() ||
            receiverHandle->isProxyObject())) {
      // If putComputed is called on a proxy whose target's prototype
      // is an array with a propname of 'length', then internalSetter
      // will be true, and the receiver will be a proxy.  In that case,
      // proxy wins.
      if (receiverHandle->isProxyObject()) {
        if (*descDefinedRes) {
          dpf.setValue = 1;
        } else {
          dpf = DefinePropertyFlags::getDefaultNewPropertyFlags();
        }
        return JSProxy::defineOwnProperty(
            receiverHandle,
            runtime,
            nameValPrimitiveHandle,
            dpf,
            valueHandle,
            opFlags);
      }
      SymbolID id{};
      LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);
      if (desc.flags.internalSetter) {
        return internalSetter(
            receiverHandle,
            runtime,
            id,
            desc.castToNamedPropertyDescriptorRef(),
            valueHandle,
            opFlags);
      }
      assert(
          receiverHandle->isHostObject() && "descriptor flags are impossible");
      return vmcast<HostObject>(receiverHandle.get())->set(id, *valueHandle);
    }
  }

  /// Can we add more properties?
  if (LLVM_UNLIKELY(!receiverHandle->isExtensible())) {
    if (opFlags.getThrowOnError()) {
      return runtime->raiseTypeError(
          "cannot add a new property"); // TODO: better message.
    }
    return false;
  }

  // If we have indexed storage we must check whether the property is an index,
  // and if it is, store it in indexed storage.
  if (receiverHandle->flags_.indexedStorage) {
    OptValue<uint32_t> arrayIndex;
    MutableHandle<StringPrimitive> strPrim{runtime};
    TO_ARRAY_INDEX(runtime, nameValPrimitiveHandle, strPrim, arrayIndex);
    if (arrayIndex) {
      // Check whether we need to update array's ".length" property.
      if (auto *array = dyn_vmcast<JSArray>(receiverHandle.get())) {
        if (LLVM_UNLIKELY(*arrayIndex >= JSArray::getLength(array))) {
          auto cr = putNamed_RJS(
              receiverHandle,
              runtime,
              Predefined::getSymbolID(Predefined::length),
              runtime->makeHandle(
                  HermesValue::encodeNumberValue(*arrayIndex + 1)),
              opFlags);
          if (LLVM_UNLIKELY(cr == ExecutionStatus::EXCEPTION))
            return ExecutionStatus::EXCEPTION;
          if (LLVM_UNLIKELY(!*cr))
            return false;
        }
      }

      auto result =
          setOwnIndexed(receiverHandle, runtime, *arrayIndex, valueHandle);
      if (LLVM_UNLIKELY(result == ExecutionStatus::EXCEPTION))
        return ExecutionStatus::EXCEPTION;
      if (LLVM_LIKELY(*result))
        return true;

      if (opFlags.getThrowOnError()) {
        // TODO: better message.
        return runtime->raiseTypeError("Cannot assign to read-only property");
      }
      return false;
    }
  }

  SymbolID id{};
  LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);

  // Add a new named property.
  return addOwnProperty(
      receiverHandle,
      runtime,
      id,
      DefinePropertyFlags::getDefaultNewPropertyFlags(),
      valueHandle,
      opFlags);
}

CallResult<bool> JSObject::putComputedWithReceiver_RJS(
    Handle<JSObject> selfHandle,
    Runtime *runtime,
    Handle<> nameValHandle,
    Handle<> valueHandle,
    Handle<> receiver,
    PropOpFlags opFlags) {
  assert(
      !opFlags.getMustExist() &&
      "mustExist flag cannot be used with computed properties");

  // Try the fast-path first: has "index-like" properties, the "name"
  // already is a valid integer index, selfHandle and receiver are the
  // same, and it is present in storage.
  if (selfHandle->flags_.fastIndexProperties) {
    if (auto arrayIndex = toArrayIndexFastPath(*nameValHandle)) {
      if (selfHandle.getHermesValue().getRaw() == receiver->getRaw()) {
        if (haveOwnIndexed(selfHandle.get(), runtime, *arrayIndex)) {
          auto result =
              setOwnIndexed(selfHandle, runtime, *arrayIndex, valueHandle);
          if (LLVM_UNLIKELY(result == ExecutionStatus::EXCEPTION))
            return ExecutionStatus::EXCEPTION;
          if (LLVM_LIKELY(*result))
            return true;
          if (opFlags.getThrowOnError()) {
            // TODO: better message.
            return runtime->raiseTypeError(
                "Cannot assign to read-only property");
          }
          return false;
        }
      }
    }
  }

  // If nameValHandle is an object, we should convert it to string now,
  // because toString may have side-effect, and we want to do this only
  // once.
  auto converted = toPropertyKeyIfObject(runtime, nameValHandle);
  if (LLVM_UNLIKELY(converted == ExecutionStatus::EXCEPTION)) {
    return ExecutionStatus::EXCEPTION;
  }
  auto nameValPrimitiveHandle = *converted;

  ComputedPropertyDescriptor desc;

  // Look for the property in this object or along the prototype chain.
  MutableHandle<JSObject> propObj{runtime};
  if (LLVM_UNLIKELY(
          getComputedPrimitiveDescriptor(
              selfHandle, runtime, nameValPrimitiveHandle, propObj, desc) ==
          ExecutionStatus::EXCEPTION)) {
    return ExecutionStatus::EXCEPTION;
  }

  // If the property exists (or, we hit a proxy/hostobject on the way
  // up the chain)
  if (propObj) {
    // Get the simple case out of the way: If the property already
    // exists on selfHandle, is not an accessor, selfHandle and
    // receiver are the same, selfHandle is not a host
    // object/proxy/internal setter, and the property is writable,
    // just write into the same slot.

    if (LLVM_LIKELY(
            selfHandle == propObj &&
            selfHandle.getHermesValue().getRaw() == receiver->getRaw() &&
            !desc.flags.accessor && !desc.flags.internalSetter &&
            !desc.flags.hostObject && !desc.flags.proxyObject &&
            desc.flags.writable)) {
      if (LLVM_UNLIKELY(
              setComputedSlotValue(selfHandle, runtime, desc, valueHandle) ==
              ExecutionStatus::EXCEPTION)) {
        return ExecutionStatus::EXCEPTION;
      }
      return true;
    }

    // Is it an accessor?
    if (LLVM_UNLIKELY(desc.flags.accessor)) {
      auto *accessor = vmcast<PropertyAccessor>(
          getComputedSlotValue(propObj.get(), runtime, desc));

      // If it is a read-only accessor, fail.
      if (!accessor->setter) {
        if (opFlags.getThrowOnError()) {
          return runtime->raiseTypeErrorForValue(
              "Cannot assign to property ",
              nameValPrimitiveHandle,
              " which has only a getter");
        }
        return false;
      }

      // Execute the accessor on this object.
      if (accessor->setter.get(runtime)->executeCall1(
              runtime->makeHandle(accessor->setter),
              runtime,
              receiver,
              valueHandle.get()) == ExecutionStatus::EXCEPTION) {
        return ExecutionStatus::EXCEPTION;
      }
      return true;
    }

    if (LLVM_UNLIKELY(desc.flags.proxyObject)) {
      assert(
          !opFlags.getMustExist() &&
          "MustExist cannot be used with Proxy objects");
      CallResult<Handle<>> key = toPropertyKey(runtime, nameValPrimitiveHandle);
      if (key == ExecutionStatus::EXCEPTION)
        return ExecutionStatus::EXCEPTION;
      CallResult<bool> setRes =
          JSProxy::setComputed(propObj, runtime, *key, valueHandle, receiver);
      if (LLVM_UNLIKELY(setRes == ExecutionStatus::EXCEPTION)) {
        return ExecutionStatus::EXCEPTION;
      }
      if (!*setRes && opFlags.getThrowOnError()) {
        // TODO: better message.
        return runtime->raiseTypeError(
            TwineChar16("Proxy trap returned false for property"));
      }
      return setRes;
    }

    if (LLVM_UNLIKELY(!desc.flags.writable)) {
      if (desc.flags.staticBuiltin) {
        SymbolID id{};
        LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);
        return raiseErrorForOverridingStaticBuiltin(
            selfHandle, runtime, runtime->makeHandle(id));
      }
      if (opFlags.getThrowOnError()) {
        return runtime->raiseTypeErrorForValue(
            "Cannot assign to read-only property ", nameValPrimitiveHandle, "");
      }
      return false;
    }

    if (selfHandle == propObj && desc.flags.internalSetter) {
      SymbolID id{};
      LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);
      return internalSetter(
          selfHandle,
          runtime,
          id,
          desc.castToNamedPropertyDescriptorRef(),
          valueHandle,
          opFlags);
    }
  }

  // The property does not exist as an conventional own property on
  // this object.

  MutableHandle<JSObject> receiverHandle{runtime, *selfHandle};
  if (selfHandle.getHermesValue().getRaw() != receiver->getRaw() ||
      receiverHandle->isHostObject() || receiverHandle->isProxyObject()) {
    if (selfHandle.getHermesValue().getRaw() != receiver->getRaw()) {
      receiverHandle = dyn_vmcast<JSObject>(*receiver);
    }
    if (!receiverHandle) {
      return false;
    }
    CallResult<bool> descDefinedRes = getOwnComputedPrimitiveDescriptor(
        receiverHandle, runtime, nameValPrimitiveHandle, IgnoreProxy::No, desc);
    if (LLVM_UNLIKELY(descDefinedRes == ExecutionStatus::EXCEPTION)) {
      return ExecutionStatus::EXCEPTION;
    }
    DefinePropertyFlags dpf;
    if (*descDefinedRes) {
      if (LLVM_UNLIKELY(desc.flags.accessor || !desc.flags.writable)) {
        return false;
      }

      if (LLVM_LIKELY(
              !desc.flags.internalSetter && !receiverHandle->isHostObject() &&
              !receiverHandle->isProxyObject())) {
        if (LLVM_UNLIKELY(
                setComputedSlotValue(
                    receiverHandle, runtime, desc, valueHandle) ==
                ExecutionStatus::EXCEPTION)) {
          return ExecutionStatus::EXCEPTION;
        }
        return true;
      }
    }

    if (LLVM_UNLIKELY(
            desc.flags.internalSetter || receiverHandle->isHostObject() ||
            receiverHandle->isProxyObject())) {
      SymbolID id{};
      LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);
      if (desc.flags.internalSetter) {
        return internalSetter(
            receiverHandle,
            runtime,
            id,
            desc.castToNamedPropertyDescriptorRef(),
            valueHandle,
            opFlags);
      } else if (receiverHandle->isHostObject()) {
        return vmcast<HostObject>(receiverHandle.get())->set(id, *valueHandle);
      }
      assert(
          receiverHandle->isProxyObject() && "descriptor flags are impossible");
      if (*descDefinedRes) {
        dpf.setValue = 1;
      } else {
        dpf = DefinePropertyFlags::getDefaultNewPropertyFlags();
      }
      return JSProxy::defineOwnProperty(
          receiverHandle,
          runtime,
          nameValPrimitiveHandle,
          dpf,
          valueHandle,
          opFlags);
    }
  }

  /// Can we add more properties?
  if (LLVM_UNLIKELY(!receiverHandle->isExtensible())) {
    if (opFlags.getThrowOnError()) {
      return runtime->raiseTypeError(
          "cannot add a new property"); // TODO: better message.
    }
    return false;
  }

  // If we have indexed storage we must check whether the property is an index,
  // and if it is, store it in indexed storage.
  if (receiverHandle->flags_.indexedStorage) {
    OptValue<uint32_t> arrayIndex;
    MutableHandle<StringPrimitive> strPrim{runtime};
    TO_ARRAY_INDEX(runtime, nameValPrimitiveHandle, strPrim, arrayIndex);
    if (arrayIndex) {
      // Check whether we need to update array's ".length" property.
      if (auto *array = dyn_vmcast<JSArray>(receiverHandle.get())) {
        if (LLVM_UNLIKELY(*arrayIndex >= JSArray::getLength(array))) {
          auto cr = putNamed_RJS(
              receiverHandle,
              runtime,
              Predefined::getSymbolID(Predefined::length),
              runtime->makeHandle(
                  HermesValue::encodeNumberValue(*arrayIndex + 1)),
              opFlags);
          if (LLVM_UNLIKELY(cr == ExecutionStatus::EXCEPTION))
            return ExecutionStatus::EXCEPTION;
          if (LLVM_UNLIKELY(!*cr))
            return false;
        }
      }

      auto result =
          setOwnIndexed(receiverHandle, runtime, *arrayIndex, valueHandle);
      if (LLVM_UNLIKELY(result == ExecutionStatus::EXCEPTION))
        return ExecutionStatus::EXCEPTION;
      if (LLVM_LIKELY(*result))
        return true;

      if (opFlags.getThrowOnError()) {
        // TODO: better message.
        return runtime->raiseTypeError("Cannot assign to read-only property");
      }
      return false;
    }
  }

  SymbolID id{};
  LAZY_TO_IDENTIFIER(runtime, nameValPrimitiveHandle, id);

  // Add a new named property.
  return addOwnProperty(
      receiverHandle,
      runtime,
      id,
      DefinePropertyFlags::getDefaultNewPropertyFlags(),
      valueHandle,
      opFlags);
}

void Compute(OpKernelContext* context) override {
  // Checks what we're remapping and inverts the relevant remapping Tensors to
  // be maps with key = old ID, value = new ID.
  std::unordered_map<int64, int64> old_row_to_new_row_map;
  std::vector<bool> row_id_present;
  const Tensor* row_remapping_t;
  OP_REQUIRES_OK(context, context->input("row_remapping", &row_remapping_t));
  const auto row_remapping = row_remapping_t->vec<int64>();
  OP_REQUIRES(context, row_remapping.size() == num_rows_,
              errors::InvalidArgument(strings::StrCat(
                  "Size of row_remapping is ", row_remapping.size(),
                  " instead of being equal to num_rows=", num_rows_)));
  OP_REQUIRES_OK(context, RemapVectorToMap(row_remapping, &row_id_present,
                                           &old_row_to_new_row_map));

  // Calculates the min/max old row ID that we need to read, to save us from
  // reading some unnecessary slices of the old tensor.
  int64 min_old_row = -1;
  int64 max_old_row = -1;
  for (int i = 0; i < row_remapping.size(); ++i) {
    if (min_old_row < 0 ||
        (row_remapping(i) >= 0 && row_remapping(i) < min_old_row)) {
      min_old_row = row_remapping(i);
    }
    if (max_old_row < 0 ||
        (row_remapping(i) >= 0 && row_remapping(i) > max_old_row)) {
      max_old_row = row_remapping(i);
    }
  }

  // Processes the remapping for columns.
  std::unordered_map<int64, int64> old_col_to_new_col_map;
  std::vector<bool> col_id_present;
  const Tensor* col_remapping_t;
  OP_REQUIRES_OK(context, context->input("col_remapping", &col_remapping_t));
  const auto col_remapping = col_remapping_t->vec<int64>();
  // Note that we always "remap rows", even when the row vocabulary does
  // not change, because partitioning requires a mapping from partitioned
  // Variables to the full checkpoints we load.
  const bool remap_cols = col_remapping.size() > 0;
  if (remap_cols) {
    OP_REQUIRES(
        context, col_remapping.size() == num_cols_,
        errors::InvalidArgument(strings::StrCat(
            "Provided col_remapping, but its size is ", col_remapping.size(),
            " instead of being equal to num_cols=", num_cols_)));
    OP_REQUIRES_OK(context, RemapVectorToMap(col_remapping, &col_id_present,
                                             &old_col_to_new_col_map));
  } else {
    col_id_present.clear();
    col_id_present.resize(num_cols_, true);
  }

  // Processes the checkpoint source and the provided Tensor name.
  const Tensor* ckpt_path_t;
  OP_REQUIRES_OK(context, context->input("ckpt_path", &ckpt_path_t));
  OP_REQUIRES(
      context, ckpt_path_t->NumElements() == 1,
      errors::InvalidArgument("The `ckpt_path` tensor must have exactly one "
                              "element, got tensor of shape ",
                              ckpt_path_t->shape().DebugString()));
  const string& ckpt_path = ckpt_path_t->scalar<tstring>()();
  const Tensor* old_tensor_name_t;
  OP_REQUIRES_OK(context,
                 context->input("old_tensor_name", &old_tensor_name_t));
  const string& old_tensor_name = old_tensor_name_t->scalar<tstring>()();

  LOG(INFO) << "Processing checkpoint : " << ckpt_path;
  BundleReader reader(context->env(), ckpt_path);
  OP_REQUIRES_OK(context, reader.status());

  DataType tensor_type;
  TensorShape tensor_shape;
  OP_REQUIRES_OK(context, reader.LookupDtypeAndShape(
                              old_tensor_name, &tensor_type, &tensor_shape));
  OP_REQUIRES(context, tensor_type == DT_FLOAT,
              errors::InvalidArgument(strings::StrCat(
                  "Tensor ", old_tensor_name, " has invalid type ",
                  DataTypeString(tensor_type), " instead of expected type ",
                  DataTypeString(DT_FLOAT))));
  // This op is limited to loading Tensors of rank 2 (matrices).
  OP_REQUIRES(
      context, tensor_shape.dims() == 2,
      errors::InvalidArgument(strings::StrCat(
          "Tensor ", old_tensor_name, " has shape ",
          tensor_shape.DebugString(), " of invalid rank ",
          tensor_shape.dims(), " instead of expected shape of rank 2.")));

  if (!remap_cols) {
    // TODO(weiho): Consider relaxing this restriction to allow partial column
    // loading (even when no column remapping is specified) if there turns out
    // to be a use case for it.
    OP_REQUIRES(context, num_cols_ == tensor_shape.dim_size(1),
                errors::InvalidArgument(strings::StrCat(
                    "Tensor ", old_tensor_name, " has shape ",
                    tensor_shape.DebugString(),
                    ", where the size of its 2nd dimension is ",
                    tensor_shape.dim_size(1),
                    " instead of being equal to num_cols=", num_cols_)));
  }

  // Uses TensorSlice to potentially load the old tensor in chunks in case
  // memory usage is a concern.
  std::vector<TensorSlice> tensor_slices;
  TensorSlice slice(tensor_shape.dims());
  if (min_old_row >= 0 && max_old_row >= 0) {
    int64 row_start = min_old_row;
    // TODO(weiho): Given the list of old row IDs of interest (the keys of
    // old_row_to_new_row_map), we could also try something smarter to
    // find some minimal set of covering ranges for the list of old row IDs
    // such that the size of each range is less than max_rows_in_memory_.
    while (row_start <= max_old_row) {
      const int64 slice_length =
          max_rows_in_memory_ <= 0
              // If max_rows_in_memory_ <= 0, we just load the entire chunk.
              ? max_old_row - row_start + 1
              : std::min(max_rows_in_memory_, max_old_row - row_start + 1);
      slice.set_start(0, row_start);
      slice.set_length(0, slice_length);
      tensor_slices.push_back(slice);
      row_start += slice_length;
    }
  }

  // Allocates the output matrix.
  Tensor* output_matrix_t = nullptr;
  OP_REQUIRES_OK(context,
                 context->allocate_output("output_matrix",
                                          TensorShape({num_rows_, num_cols_}),
                                          &output_matrix_t));
  auto output_matrix = output_matrix_t->matrix<float>();

  // Iterates through tensor slices and copies over values from the old tensor
  // to the output matrix.
  int64 row_index = min_old_row;
  int64 rows_copied = 0;
  Tensor loaded_tensor_t;
  for (const TensorSlice& tensor_slice : tensor_slices) {
    LOG(INFO) << "Loading slice " << tensor_slice.DebugString();
    TensorShape slice_shape;
    OP_REQUIRES_OK(context,
                   tensor_slice.SliceTensorShape(tensor_shape, &slice_shape));
    // Potentially re-allocates the tensor buffer since the last slice may
    // have fewer rows than the other slices.
    if (loaded_tensor_t.shape() != slice_shape) {
      loaded_tensor_t = Tensor(DT_FLOAT, slice_shape);
    }
    OP_REQUIRES_OK(context, reader.LookupSlice(old_tensor_name, tensor_slice,
                                               &loaded_tensor_t));

    // Iterates through the old loaded tensor slice row-by-row.
    for (int row = 0; row < loaded_tensor_t.dim_size(0); ++row, ++row_index) {
      if (row_index % 500000 == min_old_row) {
        LOG(INFO) << "Processing old row " << row_index;
      }

      // If the old row ID is not found in old_row_to_new_row_map, continue
      // to the next row; otherwise, copy it to the output matrix.
      const int64* new_row_ptr =
          gtl::FindOrNull(old_row_to_new_row_map, row_index);
      if (new_row_ptr == nullptr) {
        continue;
      }
      ++rows_copied;
      const int64 new_row = *new_row_ptr;

      // Copies over the row element-by-element, in case remapping is needed
      // along the column axis.
      const auto& loaded_tensor = loaded_tensor_t.matrix<float>();
      for (int old_col = 0; old_col < loaded_tensor_t.dim_size(1);
           ++old_col) {
        int64 new_col = old_col;
        if (remap_cols) {
          const int64* new_col_ptr =
              gtl::FindOrNull(old_col_to_new_col_map, old_col);
          if (new_col_ptr == nullptr) {
            // Column remapping is specified, but this column is not found in
            // old_col_to_new_col_map, so we leave it uninitialized, to be
            // filled in with initializing_values later.
            continue;
          }
          new_col = *new_col_ptr;
        }

        OP_REQUIRES(context,
                    new_row < num_rows_ && new_col < num_cols_ &&
                        new_row >= 0 && new_col >= 0,
                    errors::Internal(strings::StrCat(
                        "new_row=", new_row, " and new_col=", new_col,
                        " should have been less than num_rows_=", num_rows_,
                        " and num_cols_=", num_cols_,
                        " and non-negative. This should never have happened "
                        "if the code were correct. Please file a bug.")));
        output_matrix(new_row, new_col) = loaded_tensor(row, old_col);
      }
    }
  }
  LOG(INFO) << "Copied " << rows_copied << " rows from old matrix (with "
            << tensor_shape.dim_size(0) << " rows) to new matrix (with "
            << num_rows_ << " rows).";

  // At this point, there are potentially whole rows/columns uninitialized
  // (corresponding to the indices where row_id_present/col_id_present are
  // false). We fill this in cell-by-cell using row_id_present and
  // col_id_present while dequeuing from the initializing_values vector.
  const Tensor* initializing_values_t;
  OP_REQUIRES_OK(
      context, context->input("initializing_values", &initializing_values_t));
  const auto initializing_values = initializing_values_t->flat<float>();
  int64 initializing_values_index = 0;
  for (int i = 0; i < num_rows_; ++i) {
    for (int j = 0; j < num_cols_; ++j) {
      if (row_id_present[i] && col_id_present[j]) continue;
      OP_REQUIRES(
          context, initializing_values_index < initializing_values.size(),
          errors::InvalidArgument(
              "initializing_values contained ", initializing_values.size(),
              " elements, but more missing values remain."));
      output_matrix(i, j) = initializing_values(initializing_values_index);
      ++initializing_values_index;
    }
  }

  // Checks that we used all the given initializing values.
  OP_REQUIRES(
      context, initializing_values_index == initializing_values.size(),
      errors::InvalidArgument(
          "initializing_values contained ", initializing_values.size(),
          " elements, but only ", initializing_values_index,
          " elements were used to fill in missing values."));
}

void Compute(OpKernelContext* context) override {
  // Checks what we're remapping and inverts the relevant remapping Tensors to
  // be maps with key = old ID, value = new ID.
  std::unordered_map<int64, int64> old_row_to_new_row_map;
  std::vector<bool> row_id_present;
  const Tensor* row_remapping_t;
  OP_REQUIRES_OK(context, context->input("row_remapping", &row_remapping_t));
  const auto row_remapping = row_remapping_t->vec<int64>();
  OP_REQUIRES(context, row_remapping.size() == num_rows_,
              errors::InvalidArgument(strings::StrCat(
                  "Size of row_remapping is ", row_remapping.size(),
                  " instead of being equal to num_rows=", num_rows_)));
  OP_REQUIRES_OK(context, RemapVectorToMap(row_remapping, &row_id_present,
                                           &old_row_to_new_row_map));

  // Calculates the min/max old row ID that we need to read, to save us from
  // reading some unnecessary slices of the old tensor.
  int64 min_old_row = -1;
  int64 max_old_row = -1;
  for (int i = 0; i < row_remapping.size(); ++i) {
    if (min_old_row < 0 ||
        (row_remapping(i) >= 0 && row_remapping(i) < min_old_row)) {
      min_old_row = row_remapping(i);
    }
    if (max_old_row < 0 ||
        (row_remapping(i) >= 0 && row_remapping(i) > max_old_row)) {
      max_old_row = row_remapping(i);
    }
  }

  // Processes the remapping for columns.
  std::unordered_map<int64, int64> old_col_to_new_col_map;
  std::vector<bool> col_id_present;
  const Tensor* col_remapping_t;
  OP_REQUIRES_OK(context, context->input("col_remapping", &col_remapping_t));
  const auto col_remapping = col_remapping_t->vec<int64>();
  // Note that we always "remap rows", even when the row vocabulary does
  // not change, because partitioning requires a mapping from partitioned
  // Variables to the full checkpoints we load.
  const bool remap_cols = col_remapping.size() > 0;
  if (remap_cols) {
    OP_REQUIRES(
        context, col_remapping.size() == num_cols_,
        errors::InvalidArgument(strings::StrCat(
            "Provided col_remapping, but its size is ", col_remapping.size(),
            " instead of being equal to num_cols=", num_cols_)));
    OP_REQUIRES_OK(context, RemapVectorToMap(col_remapping, &col_id_present,
                                             &old_col_to_new_col_map));
  } else {
    col_id_present.clear();
    col_id_present.resize(num_cols_, true);
  }

  // Processes the checkpoint source and the provided Tensor name.
  const Tensor* ckpt_path_t;
  OP_REQUIRES_OK(context, context->input("ckpt_path", &ckpt_path_t));
  const string& ckpt_path = ckpt_path_t->scalar<tstring>()();
  const Tensor* old_tensor_name_t;
  OP_REQUIRES_OK(context,
                 context->input("old_tensor_name", &old_tensor_name_t));
  const string& old_tensor_name = old_tensor_name_t->scalar<tstring>()();

  LOG(INFO) << "Processing checkpoint : " << ckpt_path;
  BundleReader reader(context->env(), ckpt_path);
  OP_REQUIRES_OK(context, reader.status());

  DataType tensor_type;
  TensorShape tensor_shape;
  OP_REQUIRES_OK(context, reader.LookupDtypeAndShape(
                              old_tensor_name, &tensor_type, &tensor_shape));
  OP_REQUIRES(context, tensor_type == DT_FLOAT,
              errors::InvalidArgument(strings::StrCat(
                  "Tensor ", old_tensor_name, " has invalid type ",
                  DataTypeString(tensor_type), " instead of expected type ",
                  DataTypeString(DT_FLOAT))));
  // This op is limited to loading Tensors of rank 2 (matrices).
  OP_REQUIRES(
      context, tensor_shape.dims() == 2,
      errors::InvalidArgument(strings::StrCat(
          "Tensor ", old_tensor_name, " has shape ",
          tensor_shape.DebugString(), " of invalid rank ",
          tensor_shape.dims(), " instead of expected shape of rank 2.")));

  if (!remap_cols) {
    // TODO(weiho): Consider relaxing this restriction to allow partial column
    // loading (even when no column remapping is specified) if there turns out
    // to be a use case for it.
    OP_REQUIRES(context, num_cols_ == tensor_shape.dim_size(1),
                errors::InvalidArgument(strings::StrCat(
                    "Tensor ", old_tensor_name, " has shape ",
                    tensor_shape.DebugString(),
                    ", where the size of its 2nd dimension is ",
                    tensor_shape.dim_size(1),
                    " instead of being equal to num_cols=", num_cols_)));
  }

  // Uses TensorSlice to potentially load the old tensor in chunks in case
  // memory usage is a concern.
  std::vector<TensorSlice> tensor_slices;
  TensorSlice slice(tensor_shape.dims());
  if (min_old_row >= 0 && max_old_row >= 0) {
    int64 row_start = min_old_row;
    // TODO(weiho): Given the list of old row IDs of interest (the keys of
    // old_row_to_new_row_map), we could also try something smarter to
    // find some minimal set of covering ranges for the list of old row IDs
    // such that the size of each range is less than max_rows_in_memory_.
    while (row_start <= max_old_row) {
      const int64 slice_length =
          max_rows_in_memory_ <= 0
              // If max_rows_in_memory_ <= 0, we just load the entire chunk.
              ? max_old_row - row_start + 1
              : std::min(max_rows_in_memory_, max_old_row - row_start + 1);
      slice.set_start(0, row_start);
      slice.set_length(0, slice_length);
      tensor_slices.push_back(slice);
      row_start += slice_length;
    }
  }

  // Allocates the output matrix.
  Tensor* output_matrix_t = nullptr;
  OP_REQUIRES_OK(context,
                 context->allocate_output("output_matrix",
                                          TensorShape({num_rows_, num_cols_}),
                                          &output_matrix_t));
  auto output_matrix = output_matrix_t->matrix<float>();

  // Iterates through tensor slices and copies over values from the old tensor
  // to the output matrix.
  int64 row_index = min_old_row;
  int64 rows_copied = 0;
  Tensor loaded_tensor_t;
  for (const TensorSlice& tensor_slice : tensor_slices) {
    LOG(INFO) << "Loading slice " << tensor_slice.DebugString();
    TensorShape slice_shape;
    OP_REQUIRES_OK(context,
                   tensor_slice.SliceTensorShape(tensor_shape, &slice_shape));
    // Potentially re-allocates the tensor buffer since the last slice may
    // have fewer rows than the other slices.
    if (loaded_tensor_t.shape() != slice_shape) {
      loaded_tensor_t = Tensor(DT_FLOAT, slice_shape);
    }
    OP_REQUIRES_OK(context, reader.LookupSlice(old_tensor_name, tensor_slice,
                                               &loaded_tensor_t));

    // Iterates through the old loaded tensor slice row-by-row.
    for (int row = 0; row < loaded_tensor_t.dim_size(0); ++row, ++row_index) {
      if (row_index % 500000 == min_old_row) {
        LOG(INFO) << "Processing old row " << row_index;
      }

      // If the old row ID is not found in old_row_to_new_row_map, continue
      // to the next row; otherwise, copy it to the output matrix.
      const int64* new_row_ptr =
          gtl::FindOrNull(old_row_to_new_row_map, row_index);
      if (new_row_ptr == nullptr) {
        continue;
      }
      ++rows_copied;
      const int64 new_row = *new_row_ptr;

      // Copies over the row element-by-element, in case remapping is needed
      // along the column axis.
      const auto& loaded_tensor = loaded_tensor_t.matrix<float>();
      for (int old_col = 0; old_col < loaded_tensor_t.dim_size(1);
           ++old_col) {
        int64 new_col = old_col;
        if (remap_cols) {
          const int64* new_col_ptr =
              gtl::FindOrNull(old_col_to_new_col_map, old_col);
          if (new_col_ptr == nullptr) {
            // Column remapping is specified, but this column is not found in
            // old_col_to_new_col_map, so we leave it uninitialized, to be
            // filled in with initializing_values later.
            continue;
          }
          new_col = *new_col_ptr;
        }

        OP_REQUIRES(context,
                    new_row < num_rows_ && new_col < num_cols_ &&
                        new_row >= 0 && new_col >= 0,
                    errors::Internal(strings::StrCat(
                        "new_row=", new_row, " and new_col=", new_col,
                        " should have been less than num_rows_=", num_rows_,
                        " and num_cols_=", num_cols_,
                        " and non-negative. This should never have happened "
                        "if the code were correct. Please file a bug.")));
        output_matrix(new_row, new_col) = loaded_tensor(row, old_col);
      }
    }
  }
  LOG(INFO) << "Copied " << rows_copied << " rows from old matrix (with "
            << tensor_shape.dim_size(0) << " rows) to new matrix (with "
            << num_rows_ << " rows).";

  // At this point, there are potentially whole rows/columns uninitialized
  // (corresponding to the indices where row_id_present/col_id_present are
  // false). We fill this in cell-by-cell using row_id_present and
  // col_id_present while dequeuing from the initializing_values vector.
  const Tensor* initializing_values_t;
  OP_REQUIRES_OK(
      context, context->input("initializing_values", &initializing_values_t));
  const auto initializing_values = initializing_values_t->flat<float>();
  int64 initializing_values_index = 0;
  for (int i = 0; i < num_rows_; ++i) {
    for (int j = 0; j < num_cols_; ++j) {
      if (row_id_present[i] && col_id_present[j]) continue;
      OP_REQUIRES(
          context, initializing_values_index < initializing_values.size(),
          errors::InvalidArgument(
              "initializing_values contained ", initializing_values.size(),
              " elements, but more missing values remain."));
      output_matrix(i, j) = initializing_values(initializing_values_index);
      ++initializing_values_index;
    }
  }

  // Checks that we used all the given initializing values.
  OP_REQUIRES(
      context, initializing_values_index == initializing_values.size(),
      errors::InvalidArgument(
          "initializing_values contained ", initializing_values.size(),
          " elements, but only ", initializing_values_index,
          " elements were used to fill in missing values."));
}

  void Compute(OpKernelContext* ctx) override {
    const Tensor& shape_t = ctx->input(0);
    const Tensor& alpha_t = ctx->input(1);

    OP_REQUIRES(ctx,
                TensorShapeUtils::IsVector(shape_t.shape()) &&
                    (shape_t.dtype() == DataType::DT_INT32 ||
                     shape_t.dtype() == DataType::DT_INT64),
                errors::InvalidArgument(
                    "shape must be a vector of {int32,int64}, got shape: ",
                    shape_t.DebugString()));
    TensorShape samples_shape;
    if (shape_t.dtype() == DataType::DT_INT32) {
      auto vec = shape_t.flat<int32>();
      OP_REQUIRES_OK(ctx, TensorShapeUtils::MakeShape(vec.data(), vec.size(),
                                                      &samples_shape));
    } else if (shape_t.dtype() == DataType::DT_INT64) {
      auto vec = shape_t.flat<int64>();
      OP_REQUIRES_OK(ctx, TensorShapeUtils::MakeShape(vec.data(), vec.size(),
                                                      &samples_shape));
    }
    const int64 samples_per_alpha = samples_shape.num_elements();

    samples_shape.AppendShape(alpha_t.shape());
    // Allocate output samples.
    Tensor* samples_t = nullptr;
    OP_REQUIRES_OK(ctx, ctx->allocate_output(0, samples_shape, &samples_t));

    if (samples_shape.num_elements() == 0) return;

    using random::PhiloxRandom;

    typedef random::NormalDistribution<PhiloxRandom, double> Normal;
    typedef random::UniformDistribution<PhiloxRandom, double> Uniform;
#define UNIFORM(X)                                    \
  if (uniform_remaining == 0) {                       \
    uniform_remaining = Uniform::kResultElementCount; \
    uniform_result = uniform(&gen);                   \
  }                                                   \
  uniform_remaining--;                                \
  double X = uniform_result[uniform_remaining]

    // Each attempt is 95+% successful, and requires 1-2 normal + 1 uniform
    static constexpr int kReservedSamplesPerOutput = 256;

    const auto alpha_flat = alpha_t.flat<T>().data();
    const int64 num_alphas = alpha_t.NumElements();
    OP_REQUIRES(ctx, num_alphas > 0,
                errors::InvalidArgument(
                    "Input alpha should have non-zero element count, got: ",
                    num_alphas));
    auto samples_flat = samples_t->flat<T>().data();
    PhiloxRandom rng = generator_.ReserveRandomOutputs(
        samples_per_alpha * num_alphas, kReservedSamplesPerOutput);

    // We partition work first across alphas then across samples-per-alpha to
    // avoid a couple flops which can be done on a per-alpha basis.

    auto DoWork = [samples_per_alpha, num_alphas, &rng, samples_flat,
                   alpha_flat](int64 start_output, int64 limit_output) {
      using Eigen::numext::exp;
      using Eigen::numext::log;
      using Eigen::numext::log1p;
      using Eigen::numext::pow;

      // Capturing "rng" by-value would only make a copy for the _shared_
      // lambda.  Since we want to let each worker have its own copy, we pass
      // "rng" by reference and explicitly do a copy assignment.

      Normal normal;
      Uniform uniform;
      typename Normal::ResultType norm_result;
      typename Uniform::ResultType uniform_result;
      for (int64 output_idx = start_output; output_idx < limit_output;
           /* output_idx incremented within inner loop below */) {
        int64 alpha_idx = output_idx / samples_per_alpha;

        // Instead of +alpha_idx for each sample, we offset the pointer once.
        T* const samples_alpha_offset = samples_flat + alpha_idx;

        // Several calculations can be done on a per-alpha basis.
        const double alpha = static_cast<double>(alpha_flat[alpha_idx]);

        DISABLE_FLOAT_EQUALITY_WARNING
        if (alpha == static_cast<double>(1.0)) {
          ENABLE_FLOAT_EQUALITY_WARNING
          // Sample from an exponential distribution.
          for (int64 sample_idx = output_idx % samples_per_alpha;
               sample_idx < samples_per_alpha && output_idx < limit_output;
               sample_idx++, output_idx++) {
            // As we want data stable regardless of sharding
            // (including eventually on GPU), we skip on a per-sample basis.
            PhiloxRandom gen = rng;
            gen.Skip(kReservedSamplesPerOutput * output_idx);
            int16 uniform_remaining = 0;
            UNIFORM(u);
            const double res = -log1p(-u);
            samples_alpha_offset[sample_idx * num_alphas] = static_cast<T>(res);
          }       // for (sample_idx)
        } else {  // if alpha != 1.0
          // Transformation-rejection from pairs of uniform and normal random
          // variables. http://dl.acm.org/citation.cfm?id=358414
          //
          // The algorithm has an acceptance rate of ~95% for small alpha (~1),
          // and higher accept rates for higher alpha, so runtime is
          // O(NumAlphas * NumSamples * k) with k ~ 1 / 0.95.
          //
          // For alpha<1, we add one to d=alpha-1/3, and multiply the final
          // result by uniform()^(1/alpha)
          const bool alpha_less_than_one = alpha < 1;
          const double d = alpha + (alpha_less_than_one ? 2.0 / 3 : -1.0 / 3);
          const double c = 1.0 / 3 / sqrt(d);

          // Compute the rest of the samples for the current alpha value.
          for (int64 sample_idx = output_idx % samples_per_alpha;
               sample_idx < samples_per_alpha && output_idx < limit_output;
               sample_idx++, output_idx++) {
            // Since each sample may use a variable number of normal/uniform
            // samples, and we want data stable regardless of sharding
            // (including eventually on GPU), we skip on a per-sample basis.
            PhiloxRandom gen = rng;
            gen.Skip(kReservedSamplesPerOutput * output_idx);
            int16 norm_remaining = 0;
            int16 uniform_remaining = 0;

            // Keep trying until we don't reject a sample. In practice, we will
            // only reject ~5% at worst, for low alpha near 1.
            while (true) {
              if (norm_remaining == 0) {
                norm_remaining = Normal::kResultElementCount;
                norm_result = normal(&gen);
              }
              norm_remaining--;
              const double x = norm_result[norm_remaining];
              double v = 1 + c * x;
              if (v <= 0) {
                continue;
              }
              v = v * v * v;
              UNIFORM(u);
              // The first option in the if is a "squeeze" short-circuit to
              // dodge the two logs. Magic constant sourced from the paper
              // linked above. Upward of .91 of the area covered by the log
              // inequality is covered by the squeeze as well (larger coverage
              // for smaller values of alpha).
              if ((u < 1 - 0.0331 * (x * x) * (x * x)) ||
                  (log(u) < 0.5 * x * x + d * (1 - v + log(v)))) {
                double res = d * v;
                if (alpha_less_than_one) {
                  UNIFORM(b);
                  res *= pow(b, 1 / alpha);
                }
                samples_alpha_offset[sample_idx * num_alphas] =
                    static_cast<T>(res);
                break;
              }
            }  // while: true
          }    // for: sample_idx
        }      // if (alpha == 1.0)
      }        // for: output_idx
    };         // DoWork
#undef UNIFORM
    // Two calls to log only occur for ~10% of samples reaching the log line.
    //   2 x 100 (64-bit cycles per log) x 0.10 = ~20.
    // Other ops: sqrt, +, *, /, %... something like 15 of these, at 3-6 cycles
    // each = ~60.
    // All of this /0.95 due to the rejection possibility = ~85.
    static const int kElementCost = 85 + 2 * Normal::kElementCost +
                                    Uniform::kElementCost +
                                    3 * PhiloxRandom::kElementCost;
    auto worker_threads = *(ctx->device()->tensorflow_cpu_worker_threads());
    Shard(worker_threads.num_threads, worker_threads.workers,
          num_alphas * samples_per_alpha, kElementCost, DoWork);
  }

